from datetime import date
from hypothesis import given, assume, settings
from hypothesis import strategies as st
import pytest


def validate_date_range(start: date, end: date) -> bool:
    """Returns True if start < end, raises ValueError otherwise."""
    if start >= end:
        raise ValueError(
            f"start_date {start} must be before end_date {end}"
        )
    return True


# Property 1: valid range always returns True
@given(
    start=st.dates(min_value=date(2000, 1, 1), max_value=date(2030, 12, 30)),
    end=st.dates(min_value=date(2000, 1, 2), max_value=date(2030, 12, 31)),
)
def test_valid_range_returns_true(start, end):
    assume(start < end)  # filter to only valid cases
    assert validate_date_range(start, end) is True


# Property 2: invalid range (start >= end) always raises ValueError
@given(
    start=st.dates(min_value=date(2000, 1, 1), max_value=date(2030, 12, 31)),
    end=st.dates(min_value=date(2000, 1, 1), max_value=date(2030, 12, 31)),
)
def test_invalid_range_raises_value_error(start, end):
    assume(start >= end)  # filter to only invalid cases
    with pytest.raises(ValueError):
        validate_date_range(start, end)


# Property 3: the result is symmetric — swapping always makes it invalid
@given(
    d1=st.dates(min_value=date(2000, 1, 1), max_value=date(2030, 12, 30)),
    d2=st.dates(min_value=date(2000, 1, 2), max_value=date(2030, 12, 31)),
)
def test_swapped_dates_raise_error(d1, d2):
    assume(d1 < d2)
    # Original order is valid
    assert validate_date_range(d1, d2) is True
    # Swapped order must raise
    with pytest.raises(ValueError):
        validate_date_range(d2, d1)

from typing import List, Dict
from collections import defaultdict


def split_tests(test_ids: List[str], n_workers: int) -> List[List[str]]:
    """
    Distribute test_ids into n_workers groups using round-robin.
    Guarantees no worker gets more than one extra test vs the minimum.
    """
    if n_workers <= 0:
        raise ValueError("n_workers must be a positive integer")
    if not test_ids:
        return [[] for _ in range(n_workers)]

    groups: List[List[str]] = [[] for _ in range(n_workers)]
    for i, test_id in enumerate(test_ids):
        groups[i % n_workers].append(test_id)
    return groups


def merge_results(
    result_dicts: List[Dict[str, str]]
) -> Dict:
    """
    Merge per-worker result dicts into a summary.
    Each result_dict maps test_id -> status ('passed'/'failed'/'skipped').
    Returns total count, per-status counts, and the flat results map.
    """
    flat_results: Dict[str, str] = {}
    status_counts: Dict[str, int] = defaultdict(int)

    for worker_results in result_dicts:
        for test_id, status in worker_results.items():
            if test_id in flat_results:
                raise ValueError(
                    f"Duplicate test_id '{test_id}' found across workers"
                )
            flat_results[test_id] = status
            status_counts[status] += 1

    return {
        "total": len(flat_results),
        "passed": status_counts.get("passed", 0),
        "failed": status_counts.get("failed", 0),
        "skipped": status_counts.get("skipped", 0),
        "results": flat_results,
    }


# --- Tests ---
def test_split_even_distribution():
    groups = split_tests(["t1", "t2", "t3", "t4", "t5", "t6"], 3)
    assert len(groups) == 3
    assert all(len(g) == 2 for g in groups)
    assert sorted(sum(groups, [])) == ["t1", "t2", "t3", "t4", "t5", "t6"]


def test_split_uneven_distribution():
    groups = split_tests(["t1", "t2", "t3", "t4", "t5"], 3)
    sizes = sorted(len(g) for g in groups)
    assert sizes == [1, 2, 2]  # one worker gets one fewer test


def test_split_more_workers_than_tests():
    groups = split_tests(["t1", "t2"], 5)
    non_empty = [g for g in groups if g]
    assert len(non_empty) == 2


def test_merge_results_counts():
    r1 = {"t1": "passed", "t2": "failed"}
    r2 = {"t3": "passed", "t4": "skipped"}
    summary = merge_results([r1, r2])
    assert summary["total"] == 4
    assert summary["passed"] == 2
    assert summary["failed"] == 1
    assert summary["skipped"] == 1


def test_merge_raises_on_duplicate():
    import pytest
    r1 = {"t1": "passed"}
    r2 = {"t1": "failed"}  # duplicate across workers
    with pytest.raises(ValueError, match="Duplicate"):
        merge_results([r1, r2])
